+            // Lazy attribute patterns start with "(try " - don't use for declarations
+            if (std.mem.startsWith(u8, renamed, "(try ")) {
+                break :blk var_name;
+            }
+            break :blk renamed;
+        }
+        break :blk var_name;
+    };

